mod tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    fn create_test_events_file() -> Result<(TempDir, std::path::PathBuf)> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("sub-01_task-test_events.tsv");

        let content = "onset\tduration\ttrial_type\tresponse\n\
                       0.0\t2.0\tgolden\t1\n\
                       5.0\t2.0\tgolden\t1\n\
                       10.0\t2.0\tscrambled\t0\n\
                       15.0\t2.0\tscrambled\t0\n";

        fs::write(&file_path, content)?;
        Ok((temp_dir, file_path))
    }

    #[test]
    fn test_read_events_file() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;

        let events = read_events(&file_path)?;

        assert_eq!(events.len(), 4);
        assert_eq!(events.onset, vec![0.0, 5.0, 10.0, 15.0]);
        assert_eq!(events.duration, vec![2.0, 2.0, 2.0, 2.0]);
        assert_eq!(events.trial_type, vec!["golden", "golden", "scrambled", "scrambled"]);
        assert!(events.additional_columns.contains_key("response"));

        Ok(())
    }

    #[test]
    fn test_events_reader_configuration() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;

        let reader = EventsReader::new()
            .delimiter(b'\t')
            .include_additional(false);

        let events = reader.read_path(&file_path)?;

        assert_eq!(events.len(), 4);
        assert!(events.additional_columns.is_empty());

        Ok(())
    }

    #[test]
    fn test_event_data_filtering() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        // Filter by trial type
        let golden_events = events.filter_by_trial_type("golden");
        assert_eq!(golden_events.len(), 2);
        assert_eq!(golden_events.trial_type, vec!["golden", "golden"]);

        // Filter by time range
        let early_events = events.filter_by_time_range(0.0, 10.0);
        assert_eq!(early_events.len(), 3);

        Ok(())
    }

    #[test]
    fn test_event_summary() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        let summary = events.summary();

        assert_eq!(summary.n_events, 4);
        assert_eq!(summary.n_trial_types, 2);
        assert_eq!(summary.trial_types, vec!["golden", "scrambled"]);
        assert_eq!(summary.total_duration, 8.0);
        assert_eq!(summary.mean_duration, 2.0);
        assert_eq!(summary.min_onset, 0.0);
        assert_eq!(summary.max_onset, 15.0);

        Ok(())
    }

    #[test]
    fn test_to_records() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        let reader = EventsReader::new();
        let records = reader.to_records(&events);

        assert_eq!(records.len(), 4);
        assert_eq!(records[0].onset, 0.0);
        assert_eq!(records[0].trial_type, "golden");
        assert_eq!(records[0].additional_data.get("response"), Some(&"1".to_string()));

        Ok(())
    }

    #[test]
    fn test_unique_trial_types() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;
        let events = read_events(&file_path)?;

        let unique_types = events.unique_trial_types();
        assert_eq!(unique_types, vec!["golden", "scrambled"]);

        Ok(())
    }

    #[test]
    fn test_invalid_events_file() {
        let temp_dir = TempDir::new().unwrap();
        let file_path = temp_dir.path().join("invalid_events.tsv");

        // Missing required columns
        let content = "trial_type\tresponse\n\
                       golden\t1\n\
                       scrambled\t0\n";

        fs::write(&file_path, content).unwrap();

        let result = read_events(&file_path);
        assert!(result.is_err());
    }
}

