pub fn pca_confounds(
    confounds: HashMap<String, Vec<f64>>,
    n_components: Option<usize>,
    variance_threshold: Option<f64>,
) -> Result<PcaResult> {
    let processor = PcaProcessor::from_confound_map(confounds)?;

    match (n_components, variance_threshold) {
        (Some(n), None) => processor.compute_n_components(n),
        (None, Some(threshold)) => processor.compute_variance_threshold(threshold),
        (Some(n), Some(threshold)) => {
            let result = processor.compute_variance_threshold(threshold)?;
            if result.n_components() > n {
                processor.compute_n_components(n)
            } else {
                Ok(result)
            }
        }
        (None, None) => processor.compute(),
    }
}

