/// Check participants.tsv file
fn check_participants_file(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
    let participants_file = project.path.join("participants.tsv");
    if !participants_file.exists() {
        return Ok(()); // Already checked in check_required_files
    }

    // Read and validate participants.tsv
    let content = std::fs::read_to_string(&participants_file)?;
    let lines: Vec<&str> = content.lines().collect();

    if lines.is_empty() {
        issues.push(ComplianceIssue {
            severity: Severity::Critical,
            description: "participants.tsv is empty".to_string(),
            file: Some(participants_file.clone()),
            rule: "participants_empty".to_string(),
        });
        return Ok(());
    }

    // Check header
    let header = lines[0];
    let columns: Vec<&str> = header.split('\t').collect();

    if columns.is_empty() || columns[0] != "participant_id" {
        issues.push(ComplianceIssue {
            severity: Severity::Critical,
            description: "participants.tsv must have 'participant_id' as first column".to_string(),
            file: Some(participants_file.clone()),
            rule: "participants_header".to_string(),
        });
    }

    // Validate participant IDs
    for (i, line) in lines.iter().skip(1).enumerate() {
        if line.is_empty() { continue; }

        let fields: Vec<&str> = line.split('\t').collect();
        if fields.is_empty() { continue; }

        let participant_id = fields[0];
        if !participant_id.starts_with("sub-") {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: format!("Invalid participant ID '{}' on line {}: must start with 'sub-'", 
                                   participant_id, i + 2),
                file: Some(participants_file.clone()),
                rule: "participant_id_format".to_string(),
            });
        }

        // Check if participant directory exists
        let participant_dir = project.path.join(participant_id);
        if !participant_dir.exists() {
            issues.push(ComplianceIssue {
                severity: Severity::High,
                description: format!("Participant '{}' listed in participants.tsv but directory not found", 
                                   participant_id),
                file: Some(participants_file.clone()),
                rule: "participant_directory_missing".to_string(),
            });
        }
    }

    Ok(())
}

