//! BIDS project management
//!
//! This module provides the main [`BidsProject`] struct and related functionality
//! for managing BIDS datasets.

use std::collections::HashMap;
use std::path::{Path, PathBuf};
use std::fs;
use serde::{Deserialize, Serialize};

use crate::error::{BidsError, Result};
use crate::file::BidsFile;
use crate::search::SearchBuilder;

/// Represents a participant in a BIDS dataset
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct Participant {
    /// Participant identifier (without "sub-" prefix)
    pub id: String,
    /// Sessions associated with this participant
    pub sessions: Vec<String>,
    /// Additional metadata from participants.tsv
    pub metadata: HashMap<String, String>,
}

impl Participant {
    /// Create a new participant
    pub fn new(id: impl Into<String>) -> Self {
        Self {
            id: id.into(),
            sessions: Vec::new(),
            metadata: HashMap::new(),
        }
    }

    /// Add a session to this participant
    pub fn add_session(&mut self, session: impl Into<String>) {
        let session = session.into();
        if !self.sessions.contains(&session) {
            self.sessions.push(session);
        }
    }

    /// Add metadata for this participant
    pub fn add_metadata(&mut self, key: impl Into<String>, value: impl Into<String>) {
        self.metadata.insert(key.into(), value.into());
    }

    /// Get metadata value by key
    pub fn get_metadata(&self, key: &str) -> Option<&str> {
        self.metadata.get(key).map(|s| s.as_str())
    }
}

/// Main BIDS project representation
#[derive(Debug, Clone)]
pub struct BidsProject {
    /// Project name (typically the dataset directory name)
    pub name: String,
    /// Path to the root of the BIDS dataset
    pub path: PathBuf,
    /// List of participants in the dataset
    pub participants: Vec<Participant>,
    /// Available tasks in the dataset
    pub tasks: Vec<String>,
    /// Whether the dataset has session-level organization
    pub has_sessions: bool,
    /// Whether fMRIPrep derivatives are available
    pub has_derivatives: bool,
    /// Path to derivatives directory (if available)
    pub derivatives_path: Option<PathBuf>,
    /// Dataset description metadata
    pub description: HashMap<String, serde_json::Value>,
}

impl BidsProject {
    /// Create a new BIDS project from a directory path
    ///
    /// # Arguments
    ///
    /// * `path` - Path to the BIDS dataset root directory
    ///
    /// # Returns
    ///
    /// A new `BidsProject` instance or an error if the directory is not a valid BIDS dataset
    ///
    /// # Examples
    ///
    /// ```rust
    /// use bids_rust::BidsProject;
    /// 
    /// # fn example() -> bids_rust::Result<()> {
    /// let project = BidsProject::new("/path/to/bids/dataset")?;
    /// println!("Loaded project: {}", project.name);
    /// # Ok(())
    /// # }
    /// ```
    pub fn new<P: AsRef<Path>>(path: P) -> Result<Self> {
        let path = path.as_ref();
        let path = path.canonicalize().map_err(|e| {
            BidsError::invalid_project(path, format!("Cannot access path: {}", e))
        })?;

        // Validate basic BIDS structure
        Self::validate_bids_directory(&path)?;

        let name = path
            .file_name()
            .and_then(|n| n.to_str())
            .unwrap_or("unknown")
            .to_string();

        // Read dataset description
        let description = Self::read_dataset_description(&path)?;

        // Initialize project
        let mut project = Self {
            name,
            path: path.clone(),
            participants: Vec::new(),
            tasks: Vec::new(),
            has_sessions: false,
            has_derivatives: false,
            derivatives_path: None,
            description,
        };

        // Load participants
        project.load_participants()?;

        // Discover structure
        project.discover_structure()?;

        Ok(project)
    }

    /// Create a new BIDS project with fMRIPrep derivatives
    ///
    /// # Arguments
    ///
    /// * `path` - Path to the BIDS dataset root directory
    /// * `derivatives_path` - Optional path to derivatives directory
    ///
    /// # Returns
    ///
    /// A new `BidsProject` instance with derivatives support
    pub fn with_derivatives<P: AsRef<Path>>(
        path: P,
        derivatives_path: Option<P>,
    ) -> Result<Self> {
        let mut project = Self::new(path)?;

        if let Some(deriv_path) = derivatives_path {
            let deriv_path = deriv_path.as_ref();
            if deriv_path.exists() {
                project.has_derivatives = true;
                project.derivatives_path = Some(deriv_path.to_path_buf());
            }
        } else {
            // Look for derivatives in the standard location
            let deriv_path = project.path.join("derivatives");
            if deriv_path.exists() {
                project.has_derivatives = true;
                project.derivatives_path = Some(deriv_path);
            }
        }

        Ok(project)
    }

    /// Get participant IDs
    pub fn participants(&self) -> Vec<&str> {
        self.participants.iter().map(|p| p.id.as_str()).collect()
    }

    /// Get available tasks
    pub fn tasks(&self) -> &[String] {
        &self.tasks
    }

    /// Get available sessions (if any)
    pub fn sessions(&self) -> Vec<&str> {
        if !self.has_sessions {
            return Vec::new();
        }

        let mut sessions = Vec::new();
        for participant in &self.participants {
            for session in &participant.sessions {
                if !sessions.contains(&session.as_str()) {
                    sessions.push(session.as_str());
                }
            }
        }
        sessions.sort();
        sessions
    }

    /// Create a search builder for finding files
    pub fn search(&self) -> SearchBuilder {
        SearchBuilder::new(self)
    }

    /// Find functional scans matching criteria
    pub fn func_scans(&self) -> SearchBuilder {
        self.search().kind("bold")
    }

    /// Find preprocessed scans (requires derivatives)
    pub fn preproc_scans(&self) -> Result<SearchBuilder> {
        if !self.has_derivatives {
            return Err(BidsError::unsupported_feature(
                "Derivatives not available. Use BidsProject::with_derivatives()",
            ));
        }
        Ok(self.search().derivatives(true).desc("preproc"))
    }

    /// Find event files
    pub fn event_files(&self) -> SearchBuilder {
        self.search().suffix("events.tsv")
    }

    /// Find confound files (requires derivatives)
    pub fn confound_files(&self) -> Result<SearchBuilder> {
        if !self.has_derivatives {
            return Err(BidsError::unsupported_feature(
                "Derivatives not available. Use BidsProject::with_derivatives()",
            ));
        }
        Ok(self.search().derivatives(true).desc("confounds"))
    }

    /// Get project summary statistics
    pub fn summary(&self) -> ProjectSummary {
        // Discover modalities and count files
        let mut modalities = std::collections::HashSet::new();
        let mut n_files = 0;
        let mut total_size = 0u64;

        // Walk through the project directory to gather statistics
        if let Ok(entries) = walkdir::WalkDir::new(&self.path)
            .min_depth(1)
            .into_iter()
            .filter_map(|e| e.ok())
            .collect::<Vec<_>>()
        {
            for entry in entries {
                if entry.file_type().is_file() {
                    n_files += 1;

                    // Get file size
                    if let Ok(metadata) = entry.metadata() {
                        total_size += metadata.len();
                    }

                    // Extract modality from path
                    let path = entry.path();
                    if let Some(parent) = path.parent() {
                        if let Some(dir_name) = parent.file_name().and_then(|n| n.to_str()) {
                            let valid_modalities = vec!["anat", "func", "dwi", "fmap", "perf", "meg", "eeg", "ieeg", "beh"];
                            if valid_modalities.contains(&dir_name) {
                                modalities.insert(dir_name.to_string());
                            }
                        }
                    }
                }
            }
        }

        ProjectSummary {
            name: self.name.clone(),
            n_participants: self.participants.len(),
            n_sessions: if self.has_sessions {
                Some(self.sessions().len())
            } else {
                None
            },
            n_tasks: self.tasks.len(),
            has_derivatives: self.has_derivatives,
            modalities: modalities.into_iter().collect(),
            n_files,
            total_size: if total_size > 0 { Some(total_size) } else { None },
            tasks: self.tasks.clone(),
        }
    }

    /// Validate that a directory contains a valid BIDS dataset
    fn validate_bids_directory(path: &Path) -> Result<()> {
        if !path.is_dir() {
            return Err(BidsError::directory_not_found(path));
        }

        // Check for required files
        let participants_file = path.join("participants.tsv");
        if !participants_file.exists() {
            return Err(BidsError::invalid_project(
                path,
                "Missing required participants.tsv file",
            ));
        }

        let dataset_description = path.join("dataset_description.json");
        if !dataset_description.exists() {
            return Err(BidsError::invalid_project(
                path,
                "Missing required dataset_description.json file",
            ));
        }

        Ok(())
    }

    /// Read dataset description from JSON file
    fn read_dataset_description(path: &Path) -> Result<HashMap<String, serde_json::Value>> {
        let desc_path = path.join("dataset_description.json");
        let content = fs::read_to_string(&desc_path)?;
        let description: HashMap<String, serde_json::Value> = serde_json::from_str(&content)?;
        Ok(description)
    }

    /// Load participants from participants.tsv
    fn load_participants(&mut self) -> Result<()> {
        let participants_file = self.path.join("participants.tsv");
        let mut reader = csv::ReaderBuilder::new()
            .delimiter(b'\t')
            .from_path(&participants_file)?;

        let headers = reader.headers()?.clone();

        for result in reader.records() {
            let record = result?;

            // Extract participant ID
            let participant_id = record.get(0).ok_or_else(|| {
                BidsError::parse_error("participants.tsv", "Missing participant_id column")
            })?;

            // Remove "sub-" prefix if present
            let participant_id = participant_id.trim_start_matches("sub-");

            let mut participant = Participant::new(participant_id);

            // Add metadata from other columns
            for (i, header) in headers.iter().enumerate().skip(1) {
                if let Some(value) = record.get(i) {
                    participant.add_metadata(header, value);
                }
            }

            self.participants.push(participant);
        }

        Ok(())
    }

    /// Discover dataset structure (sessions, tasks, etc.)
    fn discover_structure(&mut self) -> Result<()> {
        // This is a placeholder for structure discovery
        // In a full implementation, this would:
        // 1. Walk through subject directories
        // 2. Discover sessions
        // 3. Discover tasks
        // 4. Build file tree

        // For now, we'll implement basic discovery
        self.discover_sessions()?;
        self.discover_tasks()?;

        Ok(())
    }

    /// Discover sessions by looking at directory structure
    fn discover_sessions(&mut self) -> Result<()> {
        for participant in &mut self.participants {
            let sub_dir = self.path.join(format!("sub-{}", participant.id));
            if sub_dir.exists() {
                for entry in fs::read_dir(&sub_dir)? {
                    let entry = entry?;
                    let path = entry.path();
                    if path.is_dir() {
                        if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
                            if name.starts_with("ses-") {
                                let session = name.trim_start_matches("ses-");
                                participant.add_session(session);
                                self.has_sessions = true;
                            }
                        }
                    }
                }
            }
        }
        Ok(())
    }

    /// Discover tasks by looking at file names
    fn discover_tasks(&mut self) -> Result<()> {
        // This is a simplified task discovery
        // In a full implementation, this would parse all BIDS files
        // For now, we'll just return an empty list
        Ok(())
    }
}

/// Project summary statistics
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProjectSummary {
    /// Project name
    pub name: String,
    /// Number of participants
    pub n_participants: usize,
    /// Number of sessions (if applicable)
    pub n_sessions: Option<usize>,
    /// Number of tasks
    pub n_tasks: usize,
    /// Whether derivatives are available
    pub has_derivatives: bool,
    /// Modalities present in the dataset
    pub modalities: Vec<String>,
    /// Total number of files
    pub n_files: usize,
    /// Dataset size in bytes
    pub total_size: Option<u64>,
    /// List of task names
    pub tasks: Vec<String>,
}

impl std::fmt::Display for ProjectSummary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "BIDS Project Summary")?;
        writeln!(f, "Project Name: {}", self.name)?;
        writeln!(f, "Participants: {}", self.n_participants)?;

        if let Some(n_sessions) = self.n_sessions {
            writeln!(f, "Sessions: {}", n_sessions)?;
        }

        writeln!(f, "Tasks: {}", self.n_tasks)?;

        if self.has_derivatives {
            writeln!(f, "Derivatives: Available")?;
        }

        if !self.tasks.is_empty() {
            writeln!(f, "Task Names: {}", self.tasks.join(", "))?;
        }

        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    fn create_minimal_bids_dataset() -> Result<TempDir> {
        let temp_dir = TempDir::new()?;
        let root = temp_dir.path();

        // Create participants.tsv
        let participants_content = "participant_id\tage\tsex\nsub-01\t25\tF\nsub-02\t30\tM\n";
        fs::write(root.join("participants.tsv"), participants_content)?;

        // Create dataset_description.json
        let dataset_description = serde_json::json!({
            "Name": "Test Dataset",
            "BIDSVersion": "1.8.0",
            "Authors": ["Test Author"]
        });
        fs::write(
            root.join("dataset_description.json"),
            serde_json::to_string_pretty(&dataset_description)?,
        )?;

        // Create minimal directory structure
        fs::create_dir_all(root.join("sub-01"))?;
        fs::create_dir_all(root.join("sub-02"))?;

        Ok(temp_dir)
    }

    #[test]
    fn test_bids_project_creation() -> Result<()> {
        let temp_dir = create_minimal_bids_dataset()?;
        let project = BidsProject::new(temp_dir.path())?;

        assert_eq!(project.participants().len(), 2);
        assert!(project.participants().contains(&"01"));
        assert!(project.participants().contains(&"02"));

        Ok(())
    }

    #[test]
    fn test_participant_creation() {
        let mut participant = Participant::new("01");
        participant.add_session("test");
        participant.add_metadata("age", "25");

        assert_eq!(participant.id, "01");
        assert_eq!(participant.sessions, vec!["test"]);
        assert_eq!(participant.get_metadata("age"), Some("25"));
    }

    #[test]
    fn test_invalid_bids_directory() {
        let temp_dir = TempDir::new().unwrap();
        let result = BidsProject::new(temp_dir.path());
        assert!(result.is_err());

        if let Err(BidsError::InvalidProject { reason, .. }) = result {
            assert!(reason.contains("participants.tsv"));
        }
    }

    #[test]
    fn test_project_summary() -> Result<()> {
        let temp_dir = create_minimal_bids_dataset()?;
        let project = BidsProject::new(temp_dir.path())?;
        let summary = project.summary();

        assert_eq!(summary.n_participants, 2);
        assert_eq!(summary.n_sessions, None);
        assert_eq!(summary.n_tasks, 0);
        assert!(!summary.has_derivatives);

        Ok(())
    }
}

